use std::collections::HashMap;

fn count_words(sentence: &str) -> HashMap<&str, usize> {
    let mut map = HashMap::new();
    sentence.split_whitespace().for_each(|word| {
        *map.entry(word).or_insert(0) += 1;
    });
    map
}

fn main() {
    let sentence = "the quick brown fox jumps over the lazy dog the fox";
    let word_count = count_words(sentence);
    assert_eq!(word_count["the"], 3);
    assert_eq!(word_count["fox"], 2);
    assert_eq!(word_count["quick"], 1);
    println!("Word counts: {:?}", word_count);
}
